import { useState, useEffect, useRef } from 'react';
import { api } from '../utils/api';

const C = {
  bg: '#0D1117', surface: '#161B22', border: '#30363D',
  text: '#E6EDF3', textSec: '#8B949E',
  green: '#3FB950', blue: '#58A6FF', purple: '#BC8CFF', amber: '#D29922',
};

function formatTime(seconds) {
  if (!seconds || seconds <= 0) return '--:--:--';
  const d = Math.floor(seconds / 86400);
  const h = Math.floor((seconds % 86400) / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  if (d > 0) return `${d}d ${h}h ${m}m`;
  if (h > 0) return `${h}h ${m}m ${s}s`;
  return `${m}m ${s}s`;
}

function formatNumber(n) {
  if (n >= 1e6) return (n / 1e6).toFixed(2) + 'M';
  if (n >= 1e3) return (n / 1e3).toFixed(1) + 'K';
  return String(n);
}

export default function GridETA() {
  const [stats, setStats] = useState(null);
  const prevCompletedRef = useRef(0);
  const rateHistoryRef = useRef({ smoothed: 0, lastTs: 0 });

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [statusRes, lbRes] = await Promise.all([
          api('/intelligence/status', { silent: true }).catch(() => null),
          api('/cluster/contributor/leaderboard?limit=20', { silent: true }).catch(() => null),
        ]);

        // Pull queue stats from intelligence status (no auth needed)
        const byStatus = statusRes?.jobs_by_status || {};
        const queued = byStatus.queued || 0;
        const completed = byStatus.completed || 0;
        const inFlight = byStatus.leased || 0;
        const total = queued + completed + inFlight + (byStatus.dead || 0);
        const workers = lbRes?.grid_totals?.online_now || 0;

        // --- Throughput: prefer rolling observed rate, then API per-worker sum ---
        // 1) API rolling rate (sum of per-worker jobs_per_min)
        const apiRatePerMin = statusRes?.throughput_jobs_per_min || 0;  // rolling jobs/min

        // 2) Track observed rate from polling deltas (exponential smoothing)
        const now = Date.now();
        const prevCompleted = prevCompletedRef.current;
        if (prevCompleted > 0 && completed > prevCompleted) {
          const delta = completed - prevCompleted;
          const elapsedSec = Math.max(1, (now - (rateHistoryRef.current.lastTs || now)) / 1000);
          const instantRate = (delta / elapsedSec) * 60; // jobs/min
          // Exponential moving average: 30% new, 70% old (smooths spikes)
          const prev = rateHistoryRef.current.smoothed || 0;
          rateHistoryRef.current.smoothed = prev > 0
            ? prev * 0.7 + instantRate * 0.3
            : instantRate;
        }
        if (completed > 0) {
          prevCompletedRef.current = completed;
          rateHistoryRef.current.lastTs = now;
        }

        // 3) Pick the best available rate (jobs/min) — NEVER fall back to lifetime total
        const observedRate = rateHistoryRef.current.smoothed || 0;
        let bestRate;
        if (observedRate > 0) {
          // We have live observed data -- most accurate
          bestRate = observedRate;
        } else if (apiRatePerMin > 0) {
          // Server-reported rolling rate (sum of per-worker jobs/min)
          bestRate = apiRatePerMin;
        } else {
          // Last resort: estimate from worker count (~40 jobs/min per worker)
          bestRate = workers > 0 ? workers * 40 : 0;
        }

        const etaSeconds = bestRate > 0 ? (queued / bestRate) * 60 : 0;
        const pct = total > 0 ? ((completed / total) * 100) : 0;

        // ETA confidence: compare observed rate vs API rate variance
        let etaConfidence = 0;
        let etaLabel = 'unknown';
        if (bestRate > 0) {
          const rateA = observedRate || 0;
          const rateB = apiRatePerMin || 0;
          if (rateA > 0 && rateB > 0) {
            const variance = Math.abs(rateA - rateB) / Math.max(rateA, rateB);
            if (variance < 0.1) { etaConfidence = 95; etaLabel = 'stable'; }
            else if (variance < 0.2) { etaConfidence = 75; etaLabel = 'stable'; }
            else if (variance < 0.4) { etaConfidence = 50; etaLabel = 'unstable'; }
            else { etaConfidence = 25; etaLabel = 'unstable'; }
          } else {
            etaConfidence = 60; etaLabel = 'estimated';
          }
        }
        // Dynamic range based on actual variance (not fixed ±30%)
        const rateA = observedRate || 0;
        const rateB = apiRatePerMin || 0;
        const actualVariance = (rateA > 0 && rateB > 0)
          ? Math.abs(rateA - rateB) / Math.max(rateA, rateB)
          : 0.3; // default 30% if only one source
        const rangeMultiplier = etaLabel === 'stable' ? 0 : Math.min(0.5, actualVariance);
        const etaLow = Math.round(etaSeconds * (1 - rangeMultiplier));
        const etaHigh = Math.round(etaSeconds * (1 + rangeMultiplier));

        const newStats = { queued, completed, total, inFlight, throughput: bestRate, workers,
                           etaSeconds, etaLow, etaHigh, etaConfidence, etaLabel, pct };
        setStats(newStats);

        // Structured dev logging
        if (import.meta.env.DEV) {
          console.log('%c[GridETA]', 'color: #58A6FF',
            `completed=${completed.toLocaleString()}(lifetime)`,
            `queued=${queued.toLocaleString()}(lifetime)`,
            `inFlight=${inFlight}(current)`,
            `rate=${Math.round(bestRate)}/min(${observedRate > 0 ? 'observed' : apiRatePerMin > 0 ? 'api_rolling' : 'estimate'})`,
            `eta=${Math.round(etaSeconds)}s`,
            `pct=${pct.toFixed(1)}%`
          );
        }
      } catch (e) {
        // silent
      }
    };

    fetchStats();
    const interval = setInterval(fetchStats, 15000);
    return () => clearInterval(interval);
  }, []);

  // (Elapsed timer removed — session-scoped timer was misleading next to lifetime completed count)

  if (!stats) return null;

  const barWidth = Math.min(stats.pct, 100);

  return (
    <div style={{
      background: C.surface, borderRadius: 8, border: `1px solid ${C.border}`,
      padding: '12px 16px', marginBottom: 12,
    }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ color: C.text, fontSize: 13, fontWeight: 600 }}>GRID PROGRESS</span>
          <span style={{
            background: stats.workers > 0 ? 'rgba(63,185,80,0.15)' : 'rgba(248,81,73,0.15)',
            color: stats.workers > 0 ? C.green : '#F85149',
            padding: '2px 8px', borderRadius: 4, fontSize: 11, fontWeight: 600,
          }}>
            {stats.workers} WORKERS
          </span>
        </div>
        <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
          <span style={{ color: C.amber, fontSize: 12, fontFamily: 'JetBrains Mono, monospace' }}>
            ETA: {stats.etaLabel === 'unstable'
              ? `${formatTime(stats.etaLow)} – ${formatTime(stats.etaHigh)}`
              : formatTime(stats.etaSeconds)}
            {stats.etaLabel === 'unstable' && stats.etaSeconds > 0 &&
              <span style={{ color: C.textSec, fontSize: 10 }}>{` (\u00B1${formatTime(stats.etaHigh - stats.etaSeconds)})`}</span>}
          </span>
          <span style={{
            fontSize: 9, fontFamily: 'JetBrains Mono, monospace', marginLeft: 4,
            padding: '2px 6px', borderRadius: 3,
            color: stats.etaLabel === 'stable' ? C.green : stats.etaLabel === 'unstable' ? C.amber : C.textSec,
            background: stats.etaLabel === 'stable' ? 'rgba(63,185,80,0.15)' : stats.etaLabel === 'unstable' ? 'rgba(210,153,34,0.15)' : 'rgba(255,255,255,0.05)',
          }}>
            {stats.etaLabel === 'stable' ? `stable` : stats.etaLabel === 'unstable' ? `unstable` : 'est.'}
          </span>
        </div>
      </div>

      {/* Progress bar (taller, with inline throughput) */}
      <div style={{
        background: '#1C2128', borderRadius: 8, height: 26, overflow: 'hidden',
        position: 'relative', marginBottom: 8,
      }}>
        <div style={{
          background: `linear-gradient(90deg, ${C.blue}, ${C.purple})`,
          width: `${barWidth}%`, height: '100%', borderRadius: 8,
          transition: 'width 1s ease',
          boxShadow: barWidth > 0 ? `0 0 8px ${C.blue}40` : 'none',
        }} />
        <span style={{
          position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)',
          color: C.text, fontSize: 12, fontWeight: 700, fontFamily: 'JetBrains Mono, monospace',
          textShadow: '0 1px 2px rgba(0,0,0,0.8)', whiteSpace: 'nowrap',
        }}>
          {stats.pct.toFixed(1)}% &middot; {Math.round(stats.throughput)}/min
        </span>
      </div>

      {/* Stats row */}
      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, fontFamily: 'JetBrains Mono, monospace' }}>
        <span style={{ color: C.green }}>{formatNumber(stats.completed)} done <span style={{ color: C.textSec, fontSize: 9 }}>(lifetime)</span></span>
        <span style={{ color: C.blue }}>{formatNumber(stats.inFlight)} in flight</span>
        <span style={{ color: C.textSec }}>{formatNumber(stats.queued)} queued</span>
        <span style={{ color: C.purple }}>{Math.round(stats.throughput)}/min <span style={{ color: C.textSec, fontSize: 9 }}>(rolling)</span></span>
      </div>
    </div>
  );
}
