/* ═══════════════════════════════════════════════════════════════════════════
   GridCompetition — Head-to-head race card, live speed bars, contribution share
   Competitive gamification panel for the Research Grid page.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useRef } from 'react';
import { api } from '../utils/api';

const T = {
  bg: '#0D1117', surface: '#161B22', surface2: '#1C2128', border: '#30363D',
  text: '#E6EDF3', textSec: '#8B949E',
  // Semantic colors (meaning only)
  green: '#3FB950',   // improving / positive
  red: '#F85149',     // degrading / negative
  amber: '#D29922',   // warning / neutral trend
  // Worker identity colors (per-device, never used for meaning)
  w1: '#58A6FF',      // worker #1 (blue)
  w2: '#3FB950',      // worker #2 (green)
  w3: '#BC8CFF',      // worker #3 (purple)
  w4: '#D29922',      // worker #4 (amber)
  w5: '#39D0D8',      // worker #5 (cyan)
  // Hardware type colors (distinct from identity + semantic)
  cpu: '#4FD1C5',     // CPU — soft cyan/teal
  gpu: '#F472B6',     // GPU — magenta/pink
  // Chart / neutral
  chart: '#39D0D8',   // throughput sparkline
  // Legacy aliases (keep for non-competition UI)
  blue: '#58A6FF', purple: '#BC8CFF', cyan: '#39D0D8',
};
const MONO = "'JetBrains Mono', ui-monospace, monospace";
const UI = "'Plus Jakarta Sans', Inter, system-ui, sans-serif";
const POLL = 15000;

// Milestone definitions
const MILESTONES = [
  { threshold: 1000, label: '1K', icon: '⚡' },
  { threshold: 10000, label: '10K', icon: '🔥' },
  { threshold: 50000, label: '50K', icon: '💎' },
  { threshold: 100000, label: '100K', icon: '👑' },
  { threshold: 250000, label: '250K', icon: '🏆' },
  { threshold: 500000, label: '500K', icon: '🌟' },
  { threshold: 1000000, label: '1M', icon: '🚀' },
];

function getMilestone(jobs) {
  let earned = null;
  let next = MILESTONES[0];
  for (const m of MILESTONES) {
    if (jobs >= m.threshold) earned = m;
    else { next = m; break; }
  }
  if (jobs >= MILESTONES[MILESTONES.length - 1].threshold) next = null;
  return { earned, next };
}

function fmt(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
  return n.toLocaleString();
}

export default function GridCompetition() {
  const [lb, setLb] = useState([]);
  const [myHost, setMyHost] = useState('TradingDesktop');
  const prevRef = useRef({});     // { hostname: jobs_completed }
  const emaRef = useRef({});      // { hostname: smoothed_rate (fast, ~15s) }
  const slowEmaRef = useRef({});  // { hostname: smoothed_rate (slow, ~60s) for trend }
  const [deltas, setDeltas] = useState({});
  const [trends, setTrends] = useState({}); // { hostname: 'up'|'down'|'stable' }

  useEffect(() => {
    const poll = () => {
      api('/cluster/contributor/leaderboard?limit=20', { silent: true }).then(res => {
        if (!res?.leaderboard) return;
        const entries = res.leaderboard;
        setLb(entries);

        // Calculate per-interval deltas with EMA smoothing
        // Keeps showing last known rate instead of zeroing on cached responses
        const newDeltas = {};
        const newTrends = {};
        for (const e of entries) {
          const prev = prevRef.current[e.hostname] || 0;
          const delta = prev > 0 ? Math.max(0, e.jobs_completed - prev) : 0;
          const instantRate = Math.round(delta / (POLL / 1000) * 60); // jobs/min
          const prevEma = emaRef.current[e.hostname] || 0;
          // Fast EMA (α=0.4, ~15s response): used for current speed
          const smoothed = delta > 0
            ? Math.round(prevEma * 0.6 + instantRate * 0.4)
            : Math.round(prevEma * 0.85);
          emaRef.current[e.hostname] = smoothed;
          newDeltas[e.hostname] = smoothed;
          // Slow EMA (α=0.15, ~60s response): used for trend comparison
          const prevSlow = slowEmaRef.current[e.hostname] || 0;
          const slow = delta > 0
            ? Math.round(prevSlow * 0.85 + instantRate * 0.15)
            : Math.round(prevSlow * 0.95);
          slowEmaRef.current[e.hostname] = slow;
          // Trend: compare fast vs slow (>10% diff = trending)
          if (slow > 0) {
            const diff = (smoothed - slow) / slow;
            newTrends[e.hostname] = diff > 0.1 ? 'up' : diff < -0.1 ? 'down' : 'stable';
          } else {
            newTrends[e.hostname] = smoothed > 0 ? 'up' : 'stable';
          }
          prevRef.current[e.hostname] = e.jobs_completed;
        }
        setDeltas(newDeltas);
        setTrends(newTrends);
      });
    };
    poll();
    const id = setInterval(poll, POLL);
    return () => clearInterval(id);
  }, []);

  if (lb.length < 2) return null;

  const totalJobs = lb.reduce((s, e) => s + (e.jobs_completed || 0), 0);
  const leader = lb[0];
  const me = lb.find(e => e.hostname === myHost) || lb[1];
  const meIdx = lb.findIndex(e => e.hostname === myHost);
  const myRank = meIdx >= 0 ? meIdx + 1 : lb.length;
  const gap = leader.jobs_completed - me.jobs_completed;
  const mySpeed = deltas[me.hostname] || 0;
  const leaderSpeed = deltas[leader.hostname] || 0;
  const speedDiff = mySpeed - leaderSpeed;
  const isLeading = me.hostname === leader.hostname;
  // Only compute catch ETA when we are actually closing the gap (speedDiff > 0)
  const etaMin = speedDiff > 0 && !isLeading && gap > 0 ? Math.round(gap / speedDiff) : null;
  const closingLabel = speedDiff > 0 ? 'closing' : speedDiff < 0 ? 'widening' : 'steady';
  const maxSpeed = Math.max(...Object.values(deltas), 1);

  // Structured dev logging for race metrics
  if (typeof window !== 'undefined' && import.meta.env.DEV) {
    console.log('%c[Race]', 'color: #BC8CFF',
      `gap=${gap.toLocaleString()}(lifetime)`,
      `mySpeed=${mySpeed}/min(rolling_15s)`,
      `leaderSpeed=${leaderSpeed}/min(rolling_15s)`,
      `closing_rate=${speedDiff}/min(${closingLabel})`,
      etaMin != null ? `catch_eta=${etaMin}min` : 'catch_eta=N/A',
    );
  }

  return (
    <div style={{
      display: 'flex', flexDirection: 'column', gap: 10,
      marginBottom: 12, fontFamily: UI,
    }}>
      {/* ── Live Speed (full width, first) ─────────────────────────── */}
      <div style={{ display: 'flex', gap: 10 }}>
        {/* Speed Bars */}
        <div style={{
          background: T.surface, borderRadius: 12, border: `1px solid ${T.border}`,
          padding: '12px 16px', flex: 1,
        }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: T.textSec, marginBottom: 12, letterSpacing: 0.5 }}>
            LIVE SPEED
          </div>
          {(() => {
            const totalClusterRate = Object.values(deltas).reduce((s, v) => s + v, 0) || 1;
            const rankColors = [T.w1, T.w2, T.w3, T.w4, T.w5];
            return lb.map((e, i) => {
              const overallRate = deltas[e.hostname] || 0;
              const hasGpu = !!(e.gpu_model && e.gpu_vram_gb > 0 && e.cuda_available);
              const gpuRate = hasGpu ? Math.round(overallRate * 0.3) : 0;
              const cpuRate = overallRate - gpuRate;
              const overallNorm = Math.min(1, overallRate / maxSpeed);
              const cpuNorm = Math.min(1, cpuRate / maxSpeed);
              const gpuNorm = hasGpu ? Math.min(1, gpuRate / maxSpeed) : 0;
              const overallOpacity = Math.max(0.4, 0.4 + 0.6 * overallNorm);
              const cpuOpacity = Math.max(0.4, 0.4 + 0.6 * cpuNorm);
              const gpuOpacity = hasGpu ? Math.max(0.4, 0.4 + 0.6 * gpuNorm) : 0.2;
              const overallW = Math.max(5, overallNorm * 100);
              const cpuW = Math.max(5, cpuNorm * 100);
              const gpuW = hasGpu ? Math.max(5, gpuNorm * 100) : 5;
              const contribPct = Math.round((overallRate / totalClusterRate) * 100);
              const trend = trends[e.hostname] || 'stable';
              const trendIcon = trend === 'up' ? '\u2191' : trend === 'down' ? '\u2193' : '\u2192';
              const trendColor = trend === 'up' ? T.green : trend === 'down' ? T.red : T.amber;
              const barColor = rankColors[i % rankColors.length];
              return (
                <div key={e.hostname} style={{ marginBottom: i < lb.length - 1 ? 14 : 0 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
                    <span style={{ fontSize: 12, color: T.text, fontWeight: 600 }}>{e.hostname}</span>
                    <span style={{ fontSize: 14, color: trendColor, fontWeight: 700 }}>{trendIcon}</span>
                  </div>
                  <div style={{ height: 8, borderRadius: 4, background: T.surface2, overflow: 'hidden', marginBottom: 2 }}>
                    <div style={{ height: '100%', borderRadius: 4, width: `${overallW}%`, background: barColor, opacity: overallOpacity, transition: 'width 0.6s ease, opacity 0.3s', boxShadow: overallRate > 0 ? `0 0 6px ${barColor}40` : 'none' }} />
                  </div>
                  <div style={{ fontSize: 9, color: T.textSec, marginBottom: 4, fontFamily: MONO }}>
                    Contribution: {contribPct}%
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
                    <div style={{ flex: 1, height: 6, borderRadius: 3, background: T.surface2, overflow: 'hidden' }}>
                      <div style={{ height: '100%', borderRadius: 3, width: `${cpuW}%`, background: T.cpu, opacity: cpuOpacity * 0.85, transition: 'width 0.6s ease' }} />
                    </div>
                    <span style={{ fontSize: 9, fontFamily: MONO, color: T.textSec, flexShrink: 0 }}>CPU — {cpuRate}/min</span>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    <div style={{ flex: 1, height: 6, borderRadius: 3, background: T.surface2, overflow: 'hidden' }}>
                      <div style={{ height: '100%', borderRadius: 3, width: `${gpuW}%`, background: T.gpu, opacity: gpuOpacity * 0.85, transition: 'width 0.6s ease' }} />
                    </div>
                    <span style={{ fontSize: 9, fontFamily: MONO, color: T.textSec, flexShrink: 0 }}>{hasGpu ? `GPU — ${gpuRate}/min` : 'GPU — inactive'}</span>
                  </div>
                </div>
              );
            });
          })()}
        </div>

      </div>

      {/* ── Compact Race Card (below live speed) ──────────────────── */}
      <div style={{
        background: T.surface, borderRadius: 12, border: `1px solid ${T.border}`,
        padding: '12px 14px', position: 'relative', overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', top: 0, left: 0, right: 0, height: 2,
          background: isLeading
            ? `linear-gradient(90deg, ${T.green}, ${T.cyan})`
            : `linear-gradient(90deg, ${T.amber}, ${T.red})`,
        }} />

        {/* Row 1: Names + speeds */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div style={{ flex: 1 }}>
            <span style={{ fontSize: 13, fontWeight: 700, color: T.green }}>{me.hostname}</span>
            <span style={{ fontSize: 12, fontFamily: MONO, color: mySpeed > 0 ? T.text : T.textSec, marginLeft: 6 }}>
              {fmt(me.jobs_completed)} {mySpeed > 0 ? `· ${mySpeed}/m` : ''}
            </span>
          </div>
          <span style={{ fontSize: 11, fontWeight: 700, color: T.textSec, margin: '0 8px' }}>VS</span>
          <div style={{ flex: 1, textAlign: 'right' }}>
            <span style={{ fontSize: 12, fontFamily: MONO, color: leaderSpeed > 0 ? T.text : T.textSec, marginRight: 6 }}>
              {leaderSpeed > 0 ? `${leaderSpeed}/m · ` : ''}{fmt(isLeading ? (lb[1]?.jobs_completed || 0) : leader.jobs_completed)}
            </span>
            <span style={{ fontSize: 13, fontWeight: 700, color: isLeading ? T.textSec : T.amber }}>
              {isLeading ? (lb[1]?.hostname || '--') : leader.hostname}
            </span>
          </div>
        </div>

        {/* Row 2: Performance bars */}
        {(() => {
          const maxR = Math.max(mySpeed, leaderSpeed, 1);
          const myW = Math.max(5, (mySpeed / maxR) * 100);
          const theirSpeed = isLeading ? (deltas[lb[1]?.hostname] || 0) : leaderSpeed;
          const theirW = Math.max(5, (theirSpeed / maxR) * 100);
          return (
            <div style={{ marginBottom: 8 }}>
              <div style={{ height: 6, borderRadius: 3, background: T.surface2, overflow: 'hidden', marginBottom: 3 }}>
                <div style={{ height: '100%', borderRadius: 3, background: T.green, width: `${myW}%`, transition: 'width 0.6s' }} />
              </div>
              <div style={{ height: 6, borderRadius: 3, background: T.surface2, overflow: 'hidden' }}>
                <div style={{ height: '100%', borderRadius: 3, background: isLeading ? T.textSec : T.amber, width: `${theirW}%`, transition: 'width 0.6s' }} />
              </div>
            </div>
          );
        })()}

        {/* Row 3: Gap · Closing Rate · ETA — single line */}
        <div style={{
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          background: T.surface2, borderRadius: 6, padding: '6px 10px',
          fontFamily: MONO, fontSize: 11,
        }}>
          <span style={{ color: T.textSec }}>
            Gap: <span style={{ color: isLeading ? T.green : T.amber, fontWeight: 700 }}>
              {isLeading ? `+${fmt(lb[0].jobs_completed - (lb[1]?.jobs_completed || 0))}` : fmt(gap)}
            </span>
          </span>
          <span style={{ color: T.textSec }}>
            {speedDiff > 0 ? 'Closing' : speedDiff < 0 ? 'Widening' : 'Steady'}:{' '}
            <span style={{ color: speedDiff > 0 ? T.green : speedDiff < 0 ? T.red : T.amber, fontWeight: 700 }}>
              {speedDiff > 0 ? `+${speedDiff}` : speedDiff < 0 ? `${speedDiff}` : '0'}/m
            </span>
          </span>
          <span style={{ color: T.textSec }}>
            ETA:{' '}
            <span style={{ color: T.cyan, fontWeight: 700 }}>
              {speedDiff > 0 && etaMin
                ? etaMin < 60 ? `${etaMin}m` : `${(etaMin / 60).toFixed(1)}h`
                : '--'}
            </span>
          </span>
        </div>
      </div>

      {/* (Live Speed + Contribution moved to top of component) */}

      {/* ── Contribution Share (full width) ──────────────────────── */}
      <div style={{
        background: T.surface, borderRadius: 12, border: `1px solid ${T.border}`,
        padding: '10px 16px',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: T.textSec, letterSpacing: 0.5, flexShrink: 0 }}>
            CONTRIBUTION
          </span>
          <div style={{ flex: 1, height: 20, borderRadius: 5, overflow: 'hidden', display: 'flex' }}>
            {lb.map((e, i) => {
              const pct = totalJobs > 0 ? (e.jobs_completed / totalJobs) * 100 : 0;
              const colors = [T.w1, T.w2, T.w3, T.w4, T.w5];
              if (pct < 1) return null;
              return <div key={e.hostname} style={{ width: `${pct}%`, background: colors[i % colors.length], transition: 'width 0.6s ease' }} />;
            })}
          </div>
          <div style={{ display: 'flex', gap: 10, flexShrink: 0 }}>
            {lb.map((e, i) => {
              const pct = totalJobs > 0 ? ((e.jobs_completed / totalJobs) * 100).toFixed(0) : '0';
              const colors = [T.w1, T.w2, T.w3, T.w4, T.w5];
              const t = trends[e.hostname] || 'stable';
              const tIcon = t === 'up' ? '\u2191' : t === 'down' ? '\u2193' : '\u2192';
              const tCol = t === 'up' ? T.green : t === 'down' ? T.red : T.textSec;
              return (
                <span key={e.hostname} style={{ fontSize: 10, fontFamily: MONO, color: colors[i % colors.length] }}>
                  {e.hostname.slice(0, 8)} {pct}%<span style={{ color: tCol }}>{tIcon}</span>
                </span>
              );
            })}
          </div>
        </div>
      </div>

      {/* Milestones moved to top bar in ResearchClusterPage */}
    </div>
  );
}
